mapper.select:
SELECT COUNT(*) FROM TB_REPORT
WHERE TARGET_TYPE = #{targetType}
  AND TARGET_SEQ  = #{targetSeq}
  AND REPORTER_SEQ = #{reporterSeq}

SELECT R.REPORT_SEQ, R.TARGET_TYPE, R.TARGET_SEQ, R.REASON, R.STATUS, DATE_FORMAT(R.CREATED_AT, '%Y.%m.%d %H:%i') AS CREATED_AT, U.NICKNAME AS REPORTER_NICKNAME, CASE WHEN R.TARGET_TYPE = 'BOARD' THEN (SELECT LEFT(TITLE, 30) FROM TB_BOARD WHERE BOARD_SEQ = R.TARGET_SEQ) WHEN R.TARGET_TYPE = 'COMMENT' THEN (SELECT LEFT(CONTENT, 30) FROM TB_COMMENT WHERE COMMENT_SEQ = R.TARGET_SEQ) END AS TARGET_TITLE FROM TB_REPORT R JOIN TB_USER U ON U.USER_SEQ = R.REPORTER_SEQ
AND R.STATUS = #{status}
ORDER BY R.REPORT_SEQ DESC
